side = int(input("Сторона куба: "))
mc.postToChat(f"Объём: {side ** 3}")
pos = mc.player.getTilePos()
for x in range(side):
    for y in range(side):
        for z in range(side):
            mc.setBlock(pos.x+x, pos.y+y, pos.z+z, block.GLASS.id)

blocks = {"камень": block.STONE.id, "золото": block.GOLD_BLOCK.id}
name = input("Какой блок? ")
pos = mc.player.getTilePos()
if name in blocks:
    mc.setBlock(pos.x, pos.y, pos.z, blocks[name])
else:
    mc.postToChat("Не знаю такой блок")

builds = [
    {"name": "Башня", "x": 10, "z": 10},
    {"name": "Мост", "x": 20, "z": 15},
]
for b in builds:
    mc.postToChat(f"{b['name']}: X={b['x']} Z={b['z']}")

import math
r = int(input("Радиус: "))
pos = mc.player.getTilePos()
for x in range(-r, r + 1):
    for z in range(-r, r + 1):
        if math.sqrt(x*x + z*z) < r:
            mc.setBlock(pos.x+x, pos.y, pos.z+z, block.GOLD_BLOCK.id)

pos = mc.player.getTilePos()
types = {mc.getBlock(pos.x + i, pos.y - 1, pos.z) for i in range(5)}
mc.postToChat(f"Разных блоков: {len(types)}")

w = int(input("Ширина: "))
L = int(input("Длина: "))
pos = mc.player.getTilePos()
for x in range(w):
    for z in range(L):
        if x % 4 == 0:
            mc.setBlock(pos.x+x, pos.y-1, pos.z+z, block.WATER.id)
        else:
            mc.setBlock(pos.x+x, pos.y-1, pos.z+z, 60)
            mc.setBlock(pos.x+x, pos.y, pos.z+z, 59)
